import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import ProductCard from '../components/ProductCard';
import { products } from '../api';

const Products = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [productsList, setProductsList] = useState([]);
  const [brands, setBrands] = useState([]);
  const [selectedBrand, setSelectedBrand] = useState(searchParams.get('brand') || '');
  const [searchQuery, setSearchQuery] = useState(searchParams.get('name') || '');

  useEffect(() => {
    const brand = searchParams.get('brand');
    const name = searchParams.get('name');
    const category = searchParams.get('category');

    setSelectedBrand(brand || '');
    setSearchQuery(name || '');

    const params = {};
    if (brand) params.brand = brand;
    if (name) params.name = name;
    if (category) params.category = category;

    products.getAll(params).then(res => {
      setProductsList(res.data);
      const uniqueBrands = [...new Set(res.data.map(p => p.brand))];
      setBrands(uniqueBrands);
    });
  }, [searchParams]);

  const handleBrandFilter = (brand) => {
    const newParams = new URLSearchParams(searchParams);
    if (brand) {
      newParams.set('brand', brand);
    } else {
      newParams.delete('brand');
    }
    setSearchParams(newParams);
  };

  const handleSearch = (e) => {
    const value = e.target.value;
    setSearchQuery(value);
    const newParams = new URLSearchParams(searchParams);
    if (value) {
      newParams.set('name', value);
    } else {
      newParams.delete('name');
    }
    setSearchParams(newParams);
  };

  const handleCategoryFilter = (category) => {
    const newParams = new URLSearchParams(searchParams);
    if (category) {
      newParams.set('category', category);
    } else {
      newParams.delete('category');
    }
    setSearchParams(newParams);
  };

  const categories = [...new Set(productsList.map(p => p.category))];

  return (
    <div className="container" style={{ padding: '48px 24px' }}>
      <motion.h1 
        className="section-title"
        initial={{ y: -20, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
      >
        Barcha Mahsulotlar
      </motion.h1>

      <motion.div 
        className="search-container"
        initial={{ y: 20, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ delay: 0.1 }}
      >
        <img src="https://img.icons8.com/ios/50/2c3e50/search--v1.png" alt="Search" className="search-icon" />
        <input
          type="text"
          className="search-input"
          placeholder="Mahsulotlarni qidirish..."
          value={searchQuery}
          onChange={handleSearch}
        />
      </motion.div>

      {brands.length > 0 && (
        <motion.div 
          className="brand-filters"
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.2 }}
        >
          <button 
            className={`brand-btn ${!selectedBrand ? 'active' : ''}`}
            onClick={() => handleBrandFilter('')}
          >
            Hammasi
          </button>
          {brands.map(brand => (
            <button
              key={brand}
              className={`brand-btn ${selectedBrand === brand ? 'active' : ''}`}
              onClick={() => handleBrandFilter(brand)}
            >
              {brand}
            </button>
          ))}
        </motion.div>
      )}

      {categories.length > 0 && (
        <motion.div 
          className="categories"
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.25 }}
        >
          <button 
            className={`category-btn ${!searchParams.get('category') ? 'active' : ''}`}
            onClick={() => handleCategoryFilter('')}
          >
            Hammasi
          </button>
          {categories.map(cat => (
            <button
              key={cat}
              className={`category-btn ${searchParams.get('category') === cat ? 'active' : ''}`}
              onClick={() => handleCategoryFilter(cat)}
            >
              {cat}
            </button>
          ))}
        </motion.div>
      )}

      <motion.div 
        className="products-grid"
        layout
      >
        <AnimatePresence mode="popLayout">
          {productsList.map((product, index) => (
            <motion.div
              key={product.id}
              layout
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.8 }}
              transition={{ delay: index * 0.03 }}
            >
              <ProductCard product={product} />
            </motion.div>
          ))}
        </AnimatePresence>
      </motion.div>

      {productsList.length === 0 && (
        <motion.div 
          className="empty"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
        >
          Mahsulotlar topilmadi
        </motion.div>
      )}
    </div>
  );
};

export default Products;
